using namespace adsk::core;
using namespace adsk::fusion;

Ptr app;
Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    app = Application::get();
    if (!app)
        return false;

    Ptr product = app->activeProduct();
    if (!product)
        return false;

    Ptr design = product;
    if (!design)
        return false;

    // Load a local material library. You'll need to edit the path to the  library.
    Ptr matLibs = app->materialLibraries();
    if (!matLibs)
        return false;

     Ptr matLib = matLibs->load("C:/Temp/APISampleMaterialLibrary2.adsklib");

    // Get the first appearance from the library.
    Ptr existingAppear = matLib->appearances()->item(0);
    if (!existingAppear)
        return false;

    // Copy the appearance into the design.
    Ptr appear = design->appearances()->addByCopy(existingAppear, existingAppear->name() + "_Copied");

    // Get the first body in the root component of the design.
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    Ptr body = rootComp->bRepBodies()->item(0);
    if (!body)
        return false;

    // Apply the appearance to the body.
    body->appearance(appear);

    if (matLib->isNative() == false)
    {
        matLib->unload();
    }

    return true;
}
